scwin.ds_List1_onbeforerowpositionchange = async function (info) {
    let row = info.oldRowIndex;

    if (scwin.chkSave == 0) {        	       

		if (ds_List1.getCellData(row, "advcdGrpCd") != ds_List1.getOriginalCellData(row, "advcdGrpCd")
			|| ds_List1.getCellData(row, "advcdPrgStsCd") != ds_List1.getOriginalCellData(row, "advcdPrgStsCd")
			|| ds_List1.getCellData(row, "bankCd") != ds_List1.getOriginalCellData(row, "bankCd")
			|| ds_List1.getCellData(row, "bankNm") != ds_List1.getOriginalCellData(row, "bankNm")
			|| ds_List1.getCellData(row, "bankAcntNo") != ds_List1.getOriginalCellData(row, "bankAcntNo")
			|| ds_List1.getCellData(row, "advcdReqAmt") != ds_List1.getOriginalCellData(row, "advcdReqAmt")
			|| ds_List1.getCellData(row, "commFeeAmt") != ds_List1.getOriginalCellData(row, "commFeeAmt")
			|| ds_List1.getCellData(row, "summary") != ds_List1.getOriginalCellData(row, "summary") ) {                        

            if (await $c.win.confirm(MSG_CM_CRM_005) == true) {
                ds_List1.undoAll();
                ds_List1.modifyAllStatus("R");
                // gr_List1.setScrollTop(gr_List1.getFocusedRowIndex());
                scwin.sChk = 0;
                scwin.chkRow = 0;
                scwin.chkSave = 0;
                ed_advcdReqSumAmt.setValue("0");	// 전도금
                ed_commFeeSumAmt.setValue("0");	// 수수료
                $c.gus.cfDisableObjects([ed_bankCd, txt_bankNm, txt_bankAcntNo, img_bankCd, ed_advcdReqAmt, ed_commFeeAmt, txt_summary]);
                $c.gus.cfEnableObjects([btn_Update]);
                $c.gus.cfDisableObjects([btn_Save]);
                return true;
            } else {
                gr_List1.setFocusedCell(row, "advcdGrpCd");
                $c.gus.cfDisableObjects([btn_Update]);
                $c.gus.cfEnableObjects([btn_Save]);
                return false;
            }
        } else {
            $c.gus.cfDisableObjects([ed_bankCd, txt_bankNm, txt_bankAcntNo, img_bankCd, ed_advcdReqAmt, ed_commFeeAmt, txt_summary]);
            $c.gus.cfEnableObjects([btn_Update]);
            $c.gus.cfDisableObjects([btn_Save]);
            return true;
        }
    }
};

scwin.ds_List1_oncelldatachange = function (info) {
    let colId = info.colID;
    if (colId == "bankCd") {
        for (var i = 0; i < ds_List1.getTotalRow(); i++) {
            if (ds_List1.getCellData(i, "chk") == "1") {
                ds_List1.setCellData(i, "bankCd", ds_List1.getCellData(row, "bankCd"));
            }
        }
    } else if (colId == "bankNm") {
        for (var i = 0; i < ds_List1.getTotalRow(); i++) {
            if (ds_List1.getCellData(i, "chk") == "1") {
                ds_List1.setCellData(i, "bankNm", ds_List1.getCellData(row, "bankNm"));
            }
        }
    } else if (colId == "bankAcntNo") {
        for (var i = 0; i < ds_List1.getTotalRow(); i++) {
            if (ds_List1.getCellData(i, "chk") == "1") {
                ds_List1.setCellData(i, "bankAcntNo", ds_List1.getCellData(row, "bankAcntNo"));
            }
        }
    }
};

scwin.gr_List1_onheaderclick = function (headerId) {    
    let arrMatched = ds_List1.getMatchedIndex("chk", "1");
    let nFocusRow = (arrMatched.length > 0) ? arrMatched[0] : "0";
    gr_List1.setFocusedCell(nFocusRow, "chk");
};
